import { Request, Response, NextFunction } from 'express';
import { CustomError } from '../utils/custom-error';
import logger from '../utils/logger';

export function errorHandlerMiddleware(err: CustomError, req: Request, res: Response, next: NextFunction): void {
  const requestId = req.headers['x-request-id'] || 'unknown';
  logger.error({
    message: err.message,
    name: err.name,
    stack: err.stack,
    requestId
  });

  const statusCode = err.statusCode || 500;
  res.status(statusCode).json({
    success: false,
    error: {
      message: err.message,
      details: err.details || 'An unexpected error occurred'
    }
  });
}

export class CustomError extends Error {
  public statusCode?: number;
  public details?: string;

  constructor(message: string, statusCode?: number, details?: string) {
    super(message);
    this.statusCode = statusCode;
    this.details = details;
  }
}

export interface DTO<T> {
  toDTO(data: T): object;
  fromDTO(dto: object): T;
}

import { DTO } from './base-dto';
import { User } from '../models/user';

export class UserDTO implements DTO<User> {
  toDTO(user: User): object {
    return {
      id: user._id,
      username: user.username,
      email: user.email,
      createdAt: user.createdAt
    };
  }

  fromDTO(dto: object): User {
    return {
      _id: dto['id'],
      username: dto['username'],
      passwordHash: '',
      email: dto['email'],
      createdAt: dto['createdAt']
    };
  }
}

import winston from 'winston';

const logger = winston.createLogger({
  level: 'info',
  format: winston.format.json(),
  defaultMeta: { service: 'user-service' },
  transports: [
    new winston.transports.Console({
      format: winston.format.combine(
        winston.format.colorize(),
        winston.format.simple()
      )
    })
  ],
});

export default logger;
